@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .

<https://example.org/kvstructure/observations> a cdi:KeyValueStructure ;
    cdi:has_DataStructureComponent <https://example.org/component/measuredValue>,
        <https://example.org/component/stationId> ;
    cdi:has_PrimaryKey <https://example.org/key/observationPK> ;
    cdi:identifier [ a cdi:Identifier ;
            cdi:uri "https://example.org/kvstructure/observations" ] ;
    cdi:isDefinedBy <https://example.org/representedVariable/observation> .
